const resp = $input.first().json;
const job_id = $('Build Gemini Payload').first().json.job_id;
const alertas_pcp = $('Build Gemini Payload').first().json.alertas_pcp || [];

if (!resp || resp.error || !resp.choices || !resp.choices[0]) {
  const msg = (resp && resp.error && resp.error.message) ? resp.error.message : 'sem resposta';
  return [{ json: { job_id: job_id, erro: true, erro_mensagem: 'OpenRouter falhou: ' + msg } }];
}

let parsed;
try {
  parsed = JSON.parse(resp.choices[0].message.content);
} catch (e) {
  return [{ json: { job_id: job_id, erro: true, erro_mensagem: 'Gemini retornou JSON inválido: ' + e.message } }];
}

const blocos = ['dados_basicos', 'dados_editoriais', 'textos', 'relacionadas'];
const ok = blocos.every(function (b) { return parsed[b] && typeof parsed[b] === 'object'; });
if (!ok) {
  return [{ json: { job_id: job_id, erro: true, erro_mensagem: 'JSON do Gemini não respeita o schema (faltam blocos)' } }];
}

function getByPath(obj, p) {
  return p.split('.').reduce(function (a, k) { return a == null ? undefined : a[k]; }, obj);
}

const alertas = alertas_pcp.slice();
const camposCriticos = [
  ['dados_basicos.titulo', 'aviso'],
  ['dados_basicos.autor', 'aviso'],
  ['dados_basicos.isbn', 'aviso'],
  ['dados_editoriais.selo', 'aviso'],
  ['textos.sinopse', 'aviso']
];
for (const item of camposCriticos) {
  const path = item[0];
  const sev = item[1];
  const v = getByPath(parsed, path);
  if (v === null || v === undefined || v === '' || (Array.isArray(v) && v.length === 0)) {
    alertas.push({ campo: path, severidade: sev, mensagem: 'Campo "' + path + '" não preenchido pelo Gemini' });
  }
}

return [{
  json: {
    job_id: job_id,
    erro: false,
    metadados_json: parsed,
    alertas: alertas,
    isbn: parsed.dados_basicos.isbn || null,
    titulo: parsed.dados_basicos.titulo || null,
    autor: parsed.dados_basicos.autor || null,
    selo: parsed.dados_editoriais.selo || null
  }
}];

const ve = $('Validate + Extract').first().json;
const dupRows = $('Check ISBN Duplicate').all();

const alertas = (ve.alertas || []).slice();

if (dupRows.length > 0 && dupRows[0].json && dupRows[0].json.id) {
  const outroId = dupRows[0].json.id;
  alertas.push({
    campo: 'dados_basicos.isbn',
    severidade: 'aviso',
    mensagem: 'Já existe outra geração com este ISBN (job ' + outroId + '). Verifique se quer manter ambas ou apagar a anterior.'
  });
}

return [{
  json: {
    job_id: ve.job_id,
    metadados_json: ve.metadados_json,
    alertas: alertas,
    isbn: ve.isbn,
    titulo: ve.titulo,
    autor: ve.autor,
    selo: ve.selo
  }
}];

const ma = $('Merge Alerts').first().json;
const edge = $input.first().json;

if (edge.error) throw new Error('Edge generate-bookinfo retornou erro: ' + edge.error);
if (!edge.xlsx_b64) throw new Error('Edge generate-bookinfo não retornou xlsx_b64');

return [{
  json: {
    job_id: ma.job_id,
    metadados_json: ma.metadados_json,
    alertas: ma.alertas,
    isbn: ma.isbn,
    titulo: ma.titulo,
    autor: ma.autor,
    selo: ma.selo,
    xlsx_bookinfo_path: ma.job_id + '/bookinfo.xlsx'
  },
  binary: {
    data: {
      data: edge.xlsx_b64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: 'bookinfo.xlsx',
      fileExtension: 'xlsx'
    }
  }
}];
